def _group_observable(name: str, display_name: Optional[str] = None) -> str:
    """Map an observable to a visualization group.

    Three taxonomies, checked in order:
    - Endothelial mechanotransduction (Koo2013 family) — keyed by the SBML
      name= attribute (display_name) since raw ids are opaque (s1..s79).
    - Heldt2002 circulation-PBPK family — UPPERCASE compartment codes
      separated by underscores (V_LV, sub_X_AO, F_AOalways).
    - Heldt2002 LPC family — lowercase compartment codes appended directly
      (Vlv, Faod, MAP, Vcor*).
    """
    # 1. Endothelial-mechanotransduction (uses SBML display name).
    if display_name and display_name in _KOO2013_GROUP_LOOKUP:
        return _KOO2013_GROUP_LOOKUP[display_name]
    # 2. circpbpk family (raw id with underscore separators).
    if name.startswith("sub_X_"):
        return "substrate_concentration"
    if name.startswith("F_AO"):
        return "aortic_flow"
    if name.startswith("V_"):
        suffix = name[2:]
        if suffix in {"LA", "LV", "RA", "RV"}:
            return "cardiac_chambers"
        if suffix in {"AO", "PA", "CO", "CR", "CRtissue"}:
            return "central_vessels"
        if suffix in {"AR", "AD"}:
            return "systemic_arteries"
        if suffix in {"MU", "GI", "LI", "KI", "SK", "OT"}:
            return "peripheral_tissue"
        if suffix in {"VE", "VC", "Pa", "PC", "PV"}:
            return "veins"
    # 3. LPC family (lookup on the full id).
    if name in _LPC_GROUP_LOOKUP:
        return _LPC_GROUP_LOOKUP[name]
    return "other"

